from math import gcd

class Solution(object):
    def maxScore(self, nums):
        n = len(nums)
        if n == 1:
            return nums[0] * nums[0]

        def lcm(a, b):
            return a * b // gcd(a, b)

        def compute(arr):
            if not arr:
                return 0
            g, l = arr[0], arr[0]
            for v in arr[1:]:
                g = gcd(g, v)
                l = lcm(l, v)
            return g * l

        # Try removing each element
        ans = compute(nums)  # remove none
        for i in range(n):
            score = compute(nums[:i] + nums[i+1:])
            ans = max(ans, score)
        return ans
